#define MAX_ARGS 10
#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000.0

// Match the C++ struct exactly: char[49] + double
// In OpenCL, double is 8 bytes. 
// Total size should be 49 + 8 = 57 bytes? 
// C++ might pad to align double? 
// C++ struct: char[49] (offset 0-48), double (offset 49?). 
// If packed, size is 57. If aligned to 8, size might be 60.
// OpenCL defaults to alignment rules similar to C. 
// To be safe and avoid -11, we explicitly match the layout.
// However, OpenCL structs passed as arguments must be power-of-2 aligned sometimes?
// The safest fix for -11 when host is fixed is to ensure the types match exactly.
// Source: double dist.
typedef struct {
    char entry[REC_LENGTH];
    double dist;
} neighbor_t;

__kernel void compute_distances(
    const char *sandbox,
    double *z,
    double target_lat,
    double target_long,
    int rec_count)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    const char *rec_iter = sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);

    double val_lat = 0.0;
    double val_long = 0.0;

    // Parse latitude
    {
        const char *p = rec_iter;
        double sign = 1.0;
        double res = 0.0;
        double frac = 0.0;
        double div = 1.0;
        int in_frac = 0;

        while (*p == ' ') p++;
        if (*p == '-') { sign = -1.0; p++; }
        else if (*p == '+') { p++; }

        while (*p != '\0' && *p != ' ' && *p != '\n' && *p != '\r') {
            if (*p == '.') {
                in_frac = 1;
                p++;
                continue;
            }
            if (*p >= '0' && *p <= '9') {
                int digit = *p - '0';
                if (!in_frac) {
                    res = res * 10.0 + (double)digit;
                } else {
                    div *= 10.0;
                    frac += (double)digit / div;
                }
            } else {
                break;
            }
            p++;
        }
        val_lat = sign * (res + frac);
    }

    // Parse longitude (offset +5)
    {
        const char *p = rec_iter + 5;
        double sign = 1.0;
        double res = 0.0;
        double frac = 0.0;
        double div = 1.0;
        int in_frac = 0;

        while (*p == ' ') p++;
        if (*p == '-') { sign = -1.0; p++; }
        else if (*p == '+') { p++; }

        while (*p != '\0' && *p != ' ' && *p != '\n' && *p != '\r') {
            if (*p == '.') {
                in_frac = 1;
                p++;
                continue;
            }
            if (*p >= '0' && *p <= '9') {
                int digit = *p - '0';
                if (!in_frac) {
                    res = res * 10.0 + (double)digit;
                } else {
                    div *= 10.0;
                    frac += (double)digit / div;
                }
            } else {
                break;
            }
            p++;
        }
        val_long = sign * (res + frac);
    }

    double diff_lat = val_lat - target_lat;
    double diff_long = val_long - target_long;
    z[i] = sqrt((diff_lat * diff_lat) + (diff_long * diff_long));
}

__kernel void update_neighbors(
    const double *z,
    const char *sandbox,
    neighbor_t *neighbors,
    int rec_count,
    int k)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    double current_dist = z[i];

    double max_dist = -1.0;
    int max_idx = 0;

    // Find the neighbor with the largest distance (the one to replace)
    for (int j = 0; j < k; j++) {
        if (neighbors[j].dist > max_dist) {
            max_dist = neighbors[j].dist;
            max_idx = j;
        }
    }

    if (current_dist < max_dist) {
        const char *src = sandbox + (i * REC_LENGTH);
        // Copy string manually to avoid alignment/struct issues
        for (int c = 0; c < REC_LENGTH - 1; c++) {
            neighbors[max_idx].entry[c] = src[c];
        }
        neighbors[max_idx].entry[REC_LENGTH - 1] = '\0';
        neighbors[max_idx].dist = current_dist;
    }
}

__kernel void init_neighbors(neighbor_t *neighbors, int k) {
    int i = get_global_id(0);
    if (i < k) {
        neighbors[i].dist = OPEN;
        for (int j = 0; j < REC_LENGTH - 1; j++) {
            neighbors[i].entry[j] = '\0';
        }
        neighbors[i].entry[REC_LENGTH - 1] = '\0';
    }
}
